/* codex ai search route guard */
(function(){
  function routePath(){
    var p = window.location.pathname || '/';
    return p.length > 1 && p.endsWith('/') ? p.slice(0, -1) : p;
  }
  function clean(){
    var active = routePath() === '/ai-search';
    var host = document.getElementById('codex-ai-search-main');
    if (!active && host) host.remove();
    if (active && !host && typeof codexAiSearchMount === 'function') codexAiSearchMount();
  }
  var push = history.pushState;
  var replace = history.replaceState;
  history.pushState = function(){ var r = push.apply(this, arguments); setTimeout(clean, 0); setTimeout(clean, 100); return r; };
  history.replaceState = function(){ var r = replace.apply(this, arguments); setTimeout(clean, 0); setTimeout(clean, 100); return r; };
  window.addEventListener('popstate', function(){ setTimeout(clean, 0); setTimeout(clean, 100); });
  document.addEventListener('click', function(event){
    var link = event.target && event.target.closest && event.target.closest('a[href]');
    if (!link) return;
    try {
      var url = new URL(link.href, window.location.href);
      var p = url.pathname || '/';
      if (p.length > 1 && p.endsWith('/')) p = p.slice(0, -1);
      if (url.origin === window.location.origin && p !== '/ai-search') {
        var host = document.getElementById('codex-ai-search-main');
        if (host) host.remove();
      }
    } catch (_) {}
  }, true);
  window.addEventListener('load', clean);
  setInterval(clean, 250);
  clean();
})();
